  (hid.\u9053\u5FB7\u503C <= 20 ? 25 : 0);
  const baseScore = abilityMean * 0.3 + courtMean * 0.3 + moralMean * 0.4;
  const score = Math.max(0, Math.min(100, Math.round(baseScore - corruptionDeduction)));
  let endingType;
