var BoundaryEventManager = class {
  constructor() {
    __publicField(this, "events", {});
  }
  register(event) {
    this.events[event.id] = event;
  }
  registerBatch(events) {
    events.forEach((event) => this.register(event));
  }
  check(params) {
    const sortedEvents = Object.values(this.events).sort((a, b) => a.priority - b.priority);
    for (const event of sortedEvents) {
      if (event.check(params)) {
        return event;
      }
    }
    return null;
  }
  checkByType(params, type) {
    const sortedEvents = Object.values(this.events).filter((event) => event.type === type).sort((a, b) => a.priority - b.priority);
    for (const event of sortedEvents) {
      if (event.check(params)) {
        return event;
      }
    }
    return null;
  }
  getAll() {
    return { ...this.events };
  }
  get(id) {
    return this.events[id];
  }
};
